test.describe('Format Utilities', () => {
  test.beforeEach(async ({ page }) => {
    // Load a page that has utilities loaded
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(1000);
  });

  test('should format currency correctly (if MekongUtils available)', async ({ page }) => {
    const result = await page.evaluate(() => {
      if ((window as any).MekongUtils && (window as any).MekongUtils.formatCurrencyVN) {
        return {
          available: true,
          test1B: (window as any).MekongUtils.formatCurrencyVN(1000000000),
          test1M: (window as any).MekongUtils.formatCurrencyVN(1000000),
          test1K: (window as any).MekongUtils.formatCurrencyVN(1000)
        };
      }
      return { available: false };
    });

    if (result.available) {
      expect(result.test1B).toBe('1.0B VNĐ');
      expect(result.test1M).toBe('1M VNĐ');
    }
    // If not available, it means scripts haven't loaded yet - that's OK
  });

  test('should have formatNumber available', async ({ page }) => {
    const result = await page.evaluate(() => {
      if ((window as any).MekongUtils && (window as any).MekongUtils.formatNumber) {
        return {
          available: true,
          test1K: (window as any).MekongUtils.formatNumber(1500),
          test1M: (window as any).MekongUtils.formatNumber(1500000)
        };
      }
      return { available: false };
    });

    if (result.available) {
      expect(result.test1K).toBe('1.5K');
      expect(result.test1M).toBe('1.5M');
    }
  });
});

test.describe('Toast Notifications', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(1000);
  });

  test('should have Toast class available', async ({ page }) => {
    const hasToast = await page.evaluate(() => {
      return typeof (window as any).Toast !== 'undefined' ||
             typeof (window as any).MekongUtils?.Toast !== 'undefined';
    });

    // Toast may or may not be loaded depending on scripts
    // This test just checks availability
    expect(typeof hasToast).toBe('boolean');
  });

  test('should display toast notification if Toast is available', async ({ page }) => {
    const result = await page.evaluate(() => {
      const Toast = (window as any).MekongUtils?.Toast || (window as any).Toast;
      if (Toast && typeof Toast.show === 'function') {
        Toast.show('Test notification', 'info');
        return { shown: true };
      }
      return { shown: false };
    });

    // If Toast is available, verify it was shown
    if (result.shown) {
      const toastVisible = await page.locator('.toast, [class*="toast"]').isVisible();
      expect(toastVisible).toBeTruthy();
    }
  });
});

test.describe('Theme Manager', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(1000);
  });

  test('should have ThemeManager available', async ({ page }) => {
    const hasThemeManager = await page.evaluate(() => {
      return typeof (window as any).ThemeManager !== 'undefined' ||
             typeof (window as any).MekongUtils?.ThemeManager !== 'undefined';
    });

    expect(typeof hasThemeManager).toBe('boolean');
  });

  test('should get current theme', async ({ page }) => {
    const theme = await page.evaluate(() => {
      const ThemeManager = (window as any).MekongUtils?.ThemeManager || (window as any).ThemeManager;
      if (ThemeManager && typeof ThemeManager.get === 'function') {
        return ThemeManager.get();
      }
      return document.documentElement.getAttribute('data-theme') || 'light';
    });

    expect(['light', 'dark']).toContain(theme);
  });
});

test.describe('String Utilities', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(1000);
  });

  test('should have slugify function', async ({ page }) => {
    const result = await page.evaluate(() => {
      if ((window as any).MekongUtils && (window as any).MekongUtils.slugify) {
        return {
          available: true,
          test1: (window as any).MekongUtils.slugify('Hello World'),
          test2: (window as any).MekongUtils.slugify('Xin Chào Việt Nam')
        };
      }
      return { available: false };
    });

    if (result.available) {
      expect(result.test1).toBe('hello-world');
      expect(result.test2).toBe('xin-chao-viet-nam');
    }
  });

  test('should have capitalize function', async ({ page }) => {
    const result = await page.evaluate(() => {
      if ((window as any).MekongUtils && (window as any).MekongUtils.capitalize) {
        return {
          available: true,
          test: (window as any).MekongUtils.capitalize('hello')
        };
      }
      return { available: false };
    });

    if (result.available) {
      expect(result.test).toBe('Hello');
    }
  });
});

test.describe('Array Utilities', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(1000);
  });

  test('should have groupBy function', async ({ page }) => {
    const result = await page.evaluate(() => {
      if ((window as any).MekongUtils && (window as any).MekongUtils.groupBy) {
        const data = [
          { name: 'Alice', role: 'admin' },
          { name: 'Bob', role: 'user' },
          { name: 'Charlie', role: 'admin' }
        ];
        return {
          available: true,
          grouped: (window as any).MekongUtils.groupBy(data, 'role')
        };
      }
      return { available: false };
    });

    if (result.available) {
      expect(result.grouped.admin.length).toBe(2);
      expect(result.grouped.user.length).toBe(1);
    }
  });

  test('should have sum function', async ({ page }) => {
    const result = await page.evaluate(() => {
      if ((window as any).MekongUtils && (window as any).MekongUtils.sum) {
        const data = [
          { name: 'A', value: 10 },
          { name: 'B', value: 20 },
          { name: 'C', value: 30 }
        ];
        return {
          available: true,
          total: (window as any).MekongUtils.sum(data, 'value')
        };
      }
      return { available: false };
    });

    if (result.available) {
      expect(result.total).toBe(60);
    }
  });
});

