test.describe('Utilities Integration Tests', () => {
  test('should use formatCurrencyVN in dashboard stats', async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(2000);

    // Revenue stat should be formatted as currency
    const revenueEl = page.locator('#stat-revenue');
    const isVisible = await revenueEl.isVisible();

    if (isVisible) {
      const text = await revenueEl.textContent();
      // Should contain VNĐ or formatted number
      expect(text?.length).toBeGreaterThan(0);
    }
  });

  test('should have formatted numbers in stat cards', async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(2000);

    // Stat cards should have formatted numbers
    const statCards = page.locator('[class*="stat"], [class*="card"]');
    const count = await statCards.count();

    expect(count).toBeGreaterThan(0);
  });
});
